import{_ as n,o as t,c as a,ag as i}from"./chunks/framework.CvgP6Fyv.js";const b=JSON.parse('{"title":"Facturering & Abonnementen","description":"","frontmatter":{},"headers":[],"relativePath":"nl/settings/billing.md","filePath":"nl/settings/billing.md"}'),r={name:"nl/settings/billing.md"};function l(o,e,d,s,g,h){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="facturering-abonnementen" tabindex="-1">Facturering &amp; Abonnementen <a class="header-anchor" href="#facturering-abonnementen" aria-label="Permalink to &quot;Facturering &amp; Abonnementen&quot;">​</a></h1><p>Beheer je MyCompanyDesk-abonnement, bekijk je verbruik en upgrade je abonnement.</p><h2 id="abonnementen" tabindex="-1">Abonnementen <a class="header-anchor" href="#abonnementen" aria-label="Permalink to &quot;Abonnementen&quot;">​</a></h2><p>MyCompanyDesk biedt drie abonnementen:</p><h3 id="gratis" tabindex="-1">Gratis <a class="header-anchor" href="#gratis" aria-label="Permalink to &quot;Gratis&quot;">​</a></h3><p>Ga gratis aan de slag:</p><ul><li>Beperkt aantal facturen en klanten</li><li>Basis uitgavenbijhouding</li><li>Basisrapportages</li><li>1 gebruiker</li><li>Community-ondersteuning</li></ul><h3 id="pro" tabindex="-1">Pro <a class="header-anchor" href="#pro" aria-label="Permalink to &quot;Pro&quot;">​</a></h3><p>Voor groeiende bedrijven:</p><ul><li>Onbeperkt facturen en klanten</li><li>Volledige uitgavenbijhouding met bonnen scannen</li><li>AI-suggesties</li><li>Aangepaste PDF-huisstijl</li><li>CSV-export</li><li>Tot 5 teamleden</li><li>E-mailondersteuning</li></ul><h3 id="business" tabindex="-1">Business <a class="header-anchor" href="#business" aria-label="Permalink to &quot;Business&quot;">​</a></h3><p>Voor teams en groeiende organisaties:</p><ul><li>Alles in Pro</li><li>Onbeperkt teamleden</li><li>API-toegang</li><li>Prioriteitsondersteuning</li><li>Geavanceerde integraties</li></ul><p>Abonnementen zijn beschikbaar in <strong>maandelijkse</strong> en <strong>jaarlijkse</strong> factureringsintervallen. Jaarabonnementen bevatten korting.</p><h2 id="je-abonnement-beheren" tabindex="-1">Je abonnement beheren <a class="header-anchor" href="#je-abonnement-beheren" aria-label="Permalink to &quot;Je abonnement beheren&quot;">​</a></h2><h3 id="upgraden" tabindex="-1">Upgraden <a class="header-anchor" href="#upgraden" aria-label="Permalink to &quot;Upgraden&quot;">​</a></h3><ol><li>Ga naar <strong>Instellingen &gt; Facturering</strong></li><li>Klik op <strong>Upgraden</strong> bij het gewenste abonnement</li><li>Voltooi de betaling via Stripe</li><li>Functies worden direct geactiveerd</li></ol><h3 id="downgraden" tabindex="-1">Downgraden <a class="header-anchor" href="#downgraden" aria-label="Permalink to &quot;Downgraden&quot;">​</a></h3><ol><li>Ga naar <strong>Instellingen &gt; Facturering</strong></li><li>Klik op <strong>Abonnement wijzigen</strong></li><li>Selecteer het lagere abonnement</li><li>Wijzigingen gaan in aan het einde van de huidige factureringsperiode</li></ol><h3 id="opzeggen" tabindex="-1">Opzeggen <a class="header-anchor" href="#opzeggen" aria-label="Permalink to &quot;Opzeggen&quot;">​</a></h3><ol><li>Ga naar <strong>Instellingen &gt; Facturering</strong></li><li>Klik op <strong>Abonnement beheren</strong> om het Stripe-factureringsportaal te openen</li><li>Zeg je abonnement op</li><li>Je behoudt toegang tot het einde van de betaalde periode</li></ol><h2 id="verbruiksoverzicht" tabindex="-1">Verbruiksoverzicht <a class="header-anchor" href="#verbruiksoverzicht" aria-label="Permalink to &quot;Verbruiksoverzicht&quot;">​</a></h2><p>Bekijk je huidige verbruik op de factureringspagina:</p><ul><li><strong>Aangemaakte facturen</strong> deze maand</li><li><strong>Klanten</strong> in je werkruimte</li><li><strong>Teamleden</strong> actief</li><li><strong>API-aanroepen</strong> (Business-abonnement)</li></ul><p>Verbruik wordt maandelijks gereset. Als je een limiet nadert, zie je een melding met upgradesuggestie.</p><h2 id="betaalmethoden" tabindex="-1">Betaalmethoden <a class="header-anchor" href="#betaalmethoden" aria-label="Permalink to &quot;Betaalmethoden&quot;">​</a></h2><p>Betalingen worden veilig verwerkt via <strong>Stripe</strong>. Geaccepteerde methoden:</p><ul><li>Creditcard (Visa, Mastercard, Amex)</li><li>Debitcard</li><li>SEPA-incasso (EU)</li></ul><p>Beheer je betaalmethode in het Stripe-factureringsportaal.</p><h2 id="factureringsportaal" tabindex="-1">Factureringsportaal <a class="header-anchor" href="#factureringsportaal" aria-label="Permalink to &quot;Factureringsportaal&quot;">​</a></h2><p>Klik op <strong>Abonnement beheren</strong> om het Stripe-factureringsportaal te openen waar je kunt:</p><ul><li>Betaalmethode bijwerken</li><li>Factuurgeschiedenis bekijken</li><li>Bonnetjes downloaden</li><li>Factureringsadres wijzigen</li></ul><h2 id="functierechten-per-abonnement" tabindex="-1">Functierechten per abonnement <a class="header-anchor" href="#functierechten-per-abonnement" aria-label="Permalink to &quot;Functierechten per abonnement&quot;">​</a></h2><p>Sommige functies zijn beperkt per abonnement:</p><table tabindex="0"><thead><tr><th>Functie</th><th>Gratis</th><th>Pro</th><th>Business</th></tr></thead><tbody><tr><td>Aangepaste huisstijl</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>CSV-export</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>Bonnen scannen</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>AI-suggesties</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>Tekstcontrole</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>API-toegang</td><td>-</td><td>-</td><td>Ja</td></tr></tbody></table><p>Bij het proberen te gebruiken van een functie op een lager abonnement wordt een upgrademelding getoond.</p>',36)])])}const p=n(r,[["render",l]]);export{b as __pageData,p as default};
